dtsPropsFor.Sparkline:
/** Series of values to plot. */
  values: number[];
  /** Stroke color (defaults to the cyan token). */
  color?: string;
  width?: number;
  height?: number;

dtsPropsFor.EquityChart:
/** One polyline per agent/strategy. */
  series: { name: string; color: string; equity: number[] }[];
  width?: number;
  height?: number;
  /** Optional dashed reference line (e.g. starting bankroll). */
  baseline?: number;

dtsPropsFor.QualityGauge:
/** Market-quality score, 0..100. */
  value: number;
  size?: number;

dtsPropsFor.ScoreHeader:
/** The serializable engine state the dashboard renders. */
  state: {
    status: "idle" | "running" | "finished";
    mode: "simulation" | "live";
    quality: number;
    fixture: { home: string; away: string; stage: string; competition: string };
    progress: { tick: number; total: number; pct: number };
    current: {
      homeGoals: number;
      awayGoals: number;
      clock: string;
      phaseLabel: string;
      suspended: boolean;
      anomaly?: string;
    } | null;
  };

dtsPropsFor.Controls:
/** Selectable fixtures for the run. */
  fixtures: { id: string; home: string; away: string; homeCode: string; awayCode: string; stage: string; status: string }[];
  status: "idle" | "running" | "finished";
  /** Whether Solana devnet anchoring is configured server-side. */
  anchorReady: boolean;

dtsPropsFor.OddsBoard:
/** Latest market tick, or null while awaiting the feed. */
  tick: {
    markets: {
      type: string;
      label: string;
      line?: number;
      selections: {
        key: string;
        label: string;
        prob: number;
        decimal: number;
        fairProb: number;
        z: number;
        prevPrice: number;
        stale: boolean;
      }[];
    }[];
    events: { kind: string; label: string; minute: number }[];
  } | null;

dtsPropsFor.SentinelFeed:
/** Live sentinel signals, newest last. */
  signals: {
    id: string;
    kind: "sharp_move" | "stale_line" | "outlier_print" | "suspended" | "reopened" | "settlement_hold";
    severity: "info" | "warning" | "critical";
    confidence: number;
    action: string;
    message: string;
  }[];
  /** Running count per signal kind. */
  counts: {
    sharp_move: number;
    stale_line: number;
    outlier_print: number;
    suspended: number;
    reopened: number;
    settlement_hold: number;
  };

dtsPropsFor.Arena:
/** Competing agents; ranked by equity internally. */
  agents: {
    id: string;
    name: string;
    mode: "taker" | "maker";
    lastRationale: string;
    curve: number[];
    metrics: {
      equity: number;
      pnl: number;
      roi: number;
      trades: number;
      hitRate: number;
      maxDrawdown: number;
    };
  }[];
  /** Id of the leading agent, or null. */
  leader: string | null;

dtsPropsFor.AuditTrail:
/** Merkle audit ledger summary + recent records. */
  ledger: {
    size: number;
    root: string;
    recent: { seq: number; kind: string; summary: string; hash: string }[];
    anchor: { sig: string; url: string; root: string } | null;
  };
  status: "idle" | "running" | "finished";
  /** Called with a record seq to open its inclusion proof. */
  onProof: (seq: number) => void;

dtsPropsFor.ProofModal:
/** Ledger record sequence to prove. */
  seq: number;
  onClose: () => void;

dtsPropsFor.SettlementCard:
/** Settlement receipt, or null before the match resolves. */
  settlement: {
    match: string;
    status: "ok" | "hold" | string;
    reason?: string;
    finalScore: { home: number; away: number };
    resolved: { marketType: string; resolvedKey: string; detail: string }[];
    proof: {
      source: string;
      verified: boolean;
      endpoint?: string;
      statKeys: string[];
      root: string;
    };
  } | null;
